// V1.1: 支持 DD 前缀 (OMS 配送单) 和纯数字 (SAP SO)
const req = $input.item.json;
let docnum = '';
if (req.query && req.query.docnum) {
  docnum = req.query.docnum;
} else {
  const url = req.headers && req.headers['x-original-url'] ? req.headers['x-original-url'] : (req.url || '');
  const parts = url.split('/');
  const lastPart = parts[parts.length - 1];
  docnum = lastPart ? lastPart.split('?')[0] : '';
}
if (!docnum || docnum === 'so' || docnum === 'undefined') {
  return { json: { _error: true, success: false, message: '请提供销售订单号' } };
}
// 支持 DD 前缀 (OMS) 或纯数字 (SAP)
let doc_source = 'sap';
if (/^[Dd]{2}\d+$/.test(docnum)) {
  doc_source = 'oms';
  docnum = docnum.toUpperCase();
} else if (/^\d+$/.test(docnum)) {
  doc_source = 'sap';
  docnum = String(parseInt(docnum, 10));
  if (docnum === 'NaN') {
    return { json: { _error: true, success: false, message: '单号解析失败' } };
  }
} else {
  return { json: { _error: true, success: false, message: '单号格式无效: ' + docnum + ' (纯数字或DD+数字)' } };
}
return { json: { _error: false, docnum: docnum, doc_source: doc_source } };

// V1.2: 合并 SAP 或 OMS 数据 + WMS 历史 (防御性 PG WMS 访问)
const docSource = $('Extract Params').item.json.doc_source || 'sap';
let dataRows = [];
try {
  if (docSource === 'oms') {
    dataRows = $('OMS查询').all().filter(r => !r.json.set_config);
  } else {
    dataRows = $('SAP查询').all().filter(r => !r.json.set_config);
  }
} catch(e) {
  const src = docSource === 'oms' ? 'OMS' : 'SAP';
  return { json: { success: false, message: src + '查询失败: ' + e.message } };
}

let wmsRows = [];
try { wmsRows = $('PG WMS').all(); } catch(e) { /* PG WMS 可能未执行 */ }

if (!dataRows || dataRows.length === 0 || !dataRows[0].json.DocNum) {
  if (docSource !== 'oms') {
    return { json: { success: false, error_type: 'not_found', message: '未找到该订单' } };
  }
  return { json: { success: false, message: '未在OMS中找到该订单' } };
}

const first = dataRows[0].json;
// 去重: PG WMS 多行导致 OMS/SAP 查询重复执行，按 LineNum 去重
const lineMap = {};
dataRows.forEach(r => { if (r.json.LineNum != null) lineMap[r.json.LineNum] = r; });
const dedupedRows = Object.values(lineMap);
const lines = dedupedRows.map(r => ({
  lineNum: r.json.LineNum,
  itemCode: r.json.ItemCode,
  itemName: r.json.ItemName || '',
  quantity: parseFloat(r.json.Quantity) || 0,
  deliveredQty: (docSource === 'oms') ? 0 : (parseFloat(r.json.DelivrdQty) || 0),
  openQty: (docSource === 'oms') ? (parseFloat(r.json.Quantity) || 0) : (parseFloat(r.json.OpenQty) || 0),
  lineStatus: r.json.LineStatus || 'O',
  uom: r.json.uom || '',
  whsCode: r.json.WhsCode || '',
  sourceDocNumber: r.json.source_doc_number || '',
  sourceLineNum: r.json.source_line_num,
  sourcePlannedQty: r.json.source_planned_qty != null ? parseFloat(r.json.source_planned_qty) : null
}));

const lineReceipts = {};
const transactions = [];
let docWmsStatus = 'pending';
for (const r of wmsRows) {
  if (r.json.doc_wms_status) docWmsStatus = r.json.doc_wms_status;
  if (r.json.id) {
    const ln = r.json.line_num;
    if (ln !== null && ln !== undefined) {
      lineReceipts[ln] = (lineReceipts[ln] || 0) + parseFloat(r.json.quantity || 0);
    }
    transactions.push({
      transaction_time: r.json.transaction_time,
      item_code: r.json.item_code || '',
      item_name: r.json.item_name || '',
      quantity: parseFloat(r.json.quantity),
      performed_by: r.json.performed_by,
      remarks: r.json.remarks || ''
    });
  }
}

// DD: 传递 oms_status 用于 split 检测
const omsStatus = first.oms_status || '';
// DD: 提取源单号列表 (抬头显示)
const sourceDocs = [...new Set(lines.filter(l => l.sourceDocNumber).map(l => l.sourceDocNumber))];

return { json: {
  success: true,
  data_source: docSource,
  sap_order: {
    docNum: String(first.DocNum),
    docEntry: first.DocEntry,
    docType: docSource === 'oms' ? 'DD' : 'SO',
    cardCode: first.CardCode || '',
    cardName: first.CardName || '',
    docDueDate: first.DocDueDate,
    docStatus: first.DocStatus || 'O',
    wmsStatus: omsStatus === 'split' ? 'split' : undefined,
    sourceDocs: sourceDocs,
    lines: lines
  },
  wms_history: {
    wms_status: docWmsStatus,
    lineReceipts: lineReceipts,
    transactions: transactions
  }
}};

// V19.4: Prepare Prefill - SAP/OMS 全量行预填入 WMS
const data = $('Merge Data').item.json;
if (!data.success || !data.sap_order || !data.sap_order.lines || data.sap_order.lines.length === 0) {
  return { json: { _prefillSql: 'SELECT 1' } };
}
const order = data.sap_order;
const docType = order.docType || 'SO';
const cc = $env.DP_COMPANY_CODE;
const user = ($('Webhook').item.json.query && $('Webhook').item.json.query.user) || 'SYSTEM';
function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  let s = String(v).substring(0, 500).replace(/\u0000/g, '');
  return "'" + s.replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
}
function escDate(v) {
  if (!v) return 'NULL';
  const d = new Date(v);
  return isNaN(d.getTime()) ? 'NULL' : "'" + d.toISOString().slice(0,10) + "'";
}
const whsCode = order.lines[0].whsCode || '';
// 去重: 防止重复 line_num 导致 ON CONFLICT 错误
const lineMap = {};
order.lines.forEach(l => { lineMap[l.lineNum] = l; });
const uniqueLines = Object.values(lineMap);
const lineVals = uniqueLines.map(l => {
  // DD: planned_qty 用 quantity (固定计划数); SO: 用 openQty (SAP 剩余)
  const plannedQty = (docType === 'DD') ? (parseFloat(l.quantity) || 0) : (parseFloat(l.openQty) || 0);
  return '((SELECT id FROM doc), ' + l.lineNum + ', ' +
  esc(l.itemCode) + ', ' + esc(l.itemName) + ', ' + esc(l.uom) + ', ' +
  plannedQty + ", 0, " + esc(l.whsCode) + ", 'pending', 'pending')";
}).join(',\n  ');
let sql = `WITH doc AS (
  INSERT INTO wms.wms_documents
    (company_code, doc_type, doc_number, sap_doc_num, sap_doc_entry,
     status, wms_status, business_partner, bp_name,
     warehouse_code, created_by, doc_date, due_date)
  VALUES (${esc(cc)}, ${esc(docType)}, ${esc(order.docNum)}, ${docType === 'DD' ? 'NULL' : esc(order.docNum)}, ${order.docEntry || 0},
     'draft',
     'pending', ${esc(order.cardCode)}, ${esc(order.cardName)},
     ${esc(whsCode)}, ${esc(user)}, CURRENT_DATE, ${escDate(order.docDueDate)})
  ON CONFLICT (company_code, doc_type, doc_number) DO UPDATE SET
    sap_doc_entry = EXCLUDED.sap_doc_entry,
    created_by = CASE WHEN wms.wms_documents.created_by = 'SYSTEM' THEN EXCLUDED.created_by ELSE wms.wms_documents.created_by END,
    business_partner = EXCLUDED.business_partner,
    bp_name = EXCLUDED.bp_name,
    due_date = EXCLUDED.due_date,
    wms_status = wms.wms_documents.wms_status,
    status = wms.wms_documents.status
  RETURNING id
)
INSERT INTO wms.wms_document_lines
  (document_id, line_num, item_code, item_name, uom,
   planned_qty, actual_qty, warehouse_code, status, wms_status)
VALUES
  ${lineVals}
ON CONFLICT (document_id, line_num) DO UPDATE SET
  item_name = EXCLUDED.item_name,
  uom = EXCLUDED.uom,
  planned_qty = EXCLUDED.planned_qty,
  warehouse_code = EXCLUDED.warehouse_code;`;
// DD: 关联 OMS→WMS (启用跨 schema 触发器同步)
if (docType === 'DD') {
  sql += ';\nUPDATE oms.orders SET wms_document_id = ' + '(SELECT id FROM wms.wms_documents WHERE company_code = ' + esc(cc) + " AND doc_type = 'DD' AND doc_number = " + esc(order.docNum) + ')' + ' WHERE company_code = ' + esc(cc) + " AND doc_type = 'DD' AND doc_number = " + esc(order.docNum) + ' AND wms_document_id IS NULL';
}
return { json: { _prefillSql: sql } };
